52	int riscv_cpu_gdb_read_register(CPUState *cs, GByteArray *mem_buf, int n)
53	{
54	    RISCVCPUClass *mcc = RISCV_CPU_GET_CLASS(cs);
55	    RISCVCPU *cpu = RISCV_CPU(cs);
56	    CPURISCVState *env = &cpu->env;
57	    target_ulong tmp;
58	
59	    if (n < 32) {
60	        tmp = env->gpr[n];
61	    } else if (n == 32) {
62	        tmp = env->pc;
63	    } else {
64	        return 0;
65	    }
66	
67	    switch (mcc->misa_mxl_max) {
68	    case MXL_RV32:
69	        return gdb_get_reg32(mem_buf, tmp);
70	    case MXL_RV64:
71	    case MXL_RV128:
72	        return gdb_get_reg64(mem_buf, tmp);
73	    default:
74	        g_assert_not_reached();
75	    }
76	    return 0;
77	}
