79	int riscv_cpu_gdb_write_register(CPUState *cs, uint8_t *mem_buf, int n)
80	{
81	    RISCVCPUClass *mcc = RISCV_CPU_GET_CLASS(cs);
82	    RISCVCPU *cpu = RISCV_CPU(cs);
83	    CPURISCVState *env = &cpu->env;
84	    int length = 0;
85	    target_ulong tmp;
86	
87	    switch (mcc->misa_mxl_max) {
88	    case MXL_RV32:
89	        tmp = (int32_t)ldl_p(mem_buf);
90	        length = 4;
91	        break;
92	    case MXL_RV64:
93	    case MXL_RV128:
94	        if (env->xl < MXL_RV64) {
95	            tmp = (int32_t)ldq_p(mem_buf);
96	        } else {
97	            tmp = ldq_p(mem_buf);
98	        }
99	        length = 8;
100	        break;
101	    default:
102	        g_assert_not_reached();
103	    }
104	    if (n > 0 && n < 32) {
105	        env->gpr[n] = tmp;
106	    } else if (n == 32) {
107	        env->pc = tmp;
108	    }
109	
110	    return length;
111	}
