113	static int riscv_gdb_get_fpu(CPUState *cs, GByteArray *buf, int n)
114	{
115	    RISCVCPU *cpu = RISCV_CPU(cs);
116	    CPURISCVState *env = &cpu->env;
117	
118	    if (n < 32) {
119	        if (env->misa_ext & RVD) {
120	            return gdb_get_reg64(buf, env->fpr[n]);
121	        }
122	        if (env->misa_ext & RVF) {
123	            return gdb_get_reg32(buf, env->fpr[n]);
124	        }
125	    }
126	    return 0;
127	}
