129	static int riscv_gdb_set_fpu(CPUState *cs, uint8_t *mem_buf, int n)
130	{
131	    RISCVCPU *cpu = RISCV_CPU(cs);
132	    CPURISCVState *env = &cpu->env;
133	
134	    if (n < 32) {
135	        env->fpr[n] = ldq_p(mem_buf); /* always 64-bit */
136	        return sizeof(uint64_t);
137	    }
138	    return 0;
139	}
