141	static int riscv_gdb_get_vector(CPUState *cs, GByteArray *buf, int n)
142	{
143	    RISCVCPU *cpu = RISCV_CPU(cs);
144	    CPURISCVState *env = &cpu->env;
145	    uint16_t vlenb = cpu->cfg.vlenb;
146	    if (n < 32) {
147	        int i;
148	        int cnt = 0;
149	        for (i = 0; i < vlenb; i += 8) {
150	            cnt += gdb_get_reg64(buf,
151	                                 env->vreg[(n * vlenb + i) / 8]);
152	        }
153	        return cnt;
154	    }
155	
156	    return 0;
157	}
