159	static int riscv_gdb_set_vector(CPUState *cs, uint8_t *mem_buf, int n)
160	{
161	    RISCVCPU *cpu = RISCV_CPU(cs);
162	    CPURISCVState *env = &cpu->env;
163	    uint16_t vlenb = cpu->cfg.vlenb;
164	    if (n < 32) {
165	        int i;
166	        for (i = 0; i < vlenb; i += 8) {
167	            env->vreg[(n * vlenb + i) / 8] = ldq_p(mem_buf + i);
168	        }
169	        return vlenb;
170	    }
171	
172	    return 0;
173	}
