175	static int riscv_gdb_get_csr(CPUState *cs, GByteArray *buf, int n)
176	{
177	    RISCVCPU *cpu = RISCV_CPU(cs);
178	    CPURISCVState *env = &cpu->env;
179	
180	    if (n < CSR_TABLE_SIZE) {
181	        target_ulong val = 0;
182	        int result;
183	
184	        result = riscv_csrrw_debug(env, n, &val, 0, 0);
185	        if (result == RISCV_EXCP_NONE) {
186	            return gdb_get_regl(buf, val);
187	        }
188	    }
189	    return 0;
190	}
