192	static int riscv_gdb_set_csr(CPUState *cs, uint8_t *mem_buf, int n)
193	{
194	    RISCVCPU *cpu = RISCV_CPU(cs);
195	    CPURISCVState *env = &cpu->env;
196	
197	    if (n < CSR_TABLE_SIZE) {
198	        target_ulong val = ldtul_p(mem_buf);
199	        int result;
200	
201	        result = riscv_csrrw_debug(env, n, NULL, val, -1);
202	        if (result == RISCV_EXCP_NONE) {
203	            return sizeof(target_ulong);
204	        }
205	    }
206	    return 0;
207	}
