209	static int riscv_gdb_get_virtual(CPUState *cs, GByteArray *buf, int n)
210	{
211	    if (n == 0) {
212	#ifdef CONFIG_USER_ONLY
213	        return gdb_get_regl(buf, 0);
214	#else
215	        RISCVCPU *cpu = RISCV_CPU(cs);
216	        CPURISCVState *env = &cpu->env;
217	
218	        return gdb_get_regl(buf, env->priv);
219	#endif
220	    }
221	    return 0;
222	}
