224	static int riscv_gdb_set_virtual(CPUState *cs, uint8_t *mem_buf, int n)
225	{
226	    if (n == 0) {
227	#ifndef CONFIG_USER_ONLY
228	        RISCVCPU *cpu = RISCV_CPU(cs);
229	        CPURISCVState *env = &cpu->env;
230	
231	        env->priv = ldtul_p(mem_buf) & 0x3;
232	        if (env->priv == PRV_RESERVED) {
233	            env->priv = PRV_S;
234	        }
235	#endif
236	        return sizeof(target_ulong);
237	    }
238	    return 0;
239	}
