241	static GDBFeature *riscv_gen_dynamic_csr_feature(CPUState *cs, int base_reg)
242	{
243	    RISCVCPUClass *mcc = RISCV_CPU_GET_CLASS(cs);
244	    RISCVCPU *cpu = RISCV_CPU(cs);
245	    CPURISCVState *env = &cpu->env;
246	    GDBFeatureBuilder builder;
247	    riscv_csr_predicate_fn predicate;
248	    int bitsize = riscv_cpu_max_xlen(mcc);
249	    const char *name;
250	    int i;
251	
252	#if !defined(CONFIG_USER_ONLY)
253	    env->debugger = true;
254	#endif
255	
256	    /* Until gdb knows about 128-bit registers */
257	    if (bitsize > 64) {
258	        bitsize = 64;
259	    }
260	
261	    gdb_feature_builder_init(&builder, &cpu->dyn_csr_feature,
262	                             "org.gnu.gdb.riscv.csr", "riscv-csr.xml",
263	                             base_reg);
264	
265	    for (i = 0; i < CSR_TABLE_SIZE; i++) {
266	        if (env->priv_ver < csr_ops[i].min_priv_ver) {
267	            continue;
268	        }
269	        predicate = csr_ops[i].predicate;
270	        if (predicate && (predicate(env, i) == RISCV_EXCP_NONE)) {
271	            name = csr_ops[i].name;
272	            if (!name) {
273	                name = g_strdup_printf("csr%03x", i);
274	            }
275	
276	            gdb_feature_builder_append_reg(&builder, name, bitsize, i,
277	                                           "int", NULL);
278	        }
279	    }
280	
281	    gdb_feature_builder_end(&builder);
282	
283	#if !defined(CONFIG_USER_ONLY)
284	    env->debugger = false;
285	#endif
286	
287	    return &cpu->dyn_csr_feature;
288	}
