331	static int andes_ace_set_reg(CPUState *cs, unsigned char *val, int reg_n)
332	{
333	    RISCVCPU *cpu = RISCV_CPU(cs);
334	    CPURISCVState *env = &cpu->env;
335	    unsigned int ByteSize = 0;
336	    unsigned int reg_idx = 0;
337	    char *type_name = NULL;
338	    uint32_t curr_reg_no = 0;
339	    AceAcrInfo *acr_info_list = env->ace_acr_info_list;
340	    unsigned int grp_idx = 0;
341	    uint32_t value_len;
342	
343	    if (acr_info_list == NULL) {
344	        return 0;
345	    }
346	
347	    /* Get acr info by ACR register number */
348	    for (unsigned int i = 0; i < env->ace_acracm_reg_number; i++) {
349	        if ((acr_info_list->num + curr_reg_no) >= reg_n + 1) {
350	            reg_idx = reg_n - curr_reg_no;
351	            grp_idx = acr_info_list->idx;
352	            type_name = acr_info_list->name;
353	            unsigned int acr_width = acr_info_list->width;
354	            ByteSize =
355	                (acr_width % 8 == 0) ? acr_width / 8 : (acr_width / 8) + 1;
356	            break;
357	        }
358	        curr_reg_no += acr_info_list->num;
359	        acr_info_list++;
360	    }
361	    if (type_name == NULL) {
362	        qemu_printf("Cannot find acr reg no %d\n", reg_n);
363	        return -1;
364	    }
365	
366	    /* value_len is stored as a 64-bit unsigned integer size */
367	    value_len = ByteSize >> 3 ? ByteSize >> 3 : 1;
368	    qemu_ace_agent_set_register(env, grp_idx, reg_idx,
369	                                (uint64_t *)val, value_len);
370	
371	    return ByteSize;
372	}
