374	static int riscv_gdb_get_ace(CPUState *cs, GByteArray *buf, int n)
375	{
376	    unsigned total_bytes = andes_ace_get_reg(cs, n);
377	    RISCVCPU *cpu = RISCV_CPU(cs);
378	    CPURISCVState *env = &cpu->env;
379	    if (total_bytes != -1) {
380	        g_byte_array_append(buf, env->ace_acr_value, total_bytes);
381	        return total_bytes;
382	    }
383	    return 0;
384	}
