386	static int riscv_gdb_set_ace(CPUState *cs, uint8_t *mem_buf, int n)
387	{
388	    unsigned total_bytes = andes_ace_set_reg(cs, mem_buf, n);
389	    if (total_bytes != -1) {
390	        return total_bytes;
391	    }
392	    return 0;
393	}
