395	static GDBFeature *riscv_gen_dynamic_ace_xml(CPUState *cs, int base_reg)
396	{
397	#if defined(CONFIG_USER_ONLY)
398	        return NULL;
399	#else
400	    RISCVCPU *cpu = RISCV_CPU(cs);
401	    GDBFeatureBuilder builder;
402	    CPURISCVState *env = &cpu->env;
403	    int num_regs = 0;
404	    AceAcrInfo *acr_info_list = env->ace_acr_info_list;
405	
406	    if (acr_info_list == NULL) {
407	        return NULL;
408	    }
409	
410	#if !defined(CONFIG_USER_ONLY)
411	    env->debugger = true;
412	#endif
413	
414	    gdb_feature_builder_init(&builder, &cpu->dyn_ace_feature,
415	                             "org.gnu.gdb.riscv.ace", "riscv-ace.xml",
416	                             base_reg);
417	
418	    for (unsigned int i = 0; i < env->ace_acracm_reg_number; i++) {
419	        unsigned int acr_number = acr_info_list->num;
420	        unsigned int acr_width = acr_info_list->width;
421	        char *acr_name = acr_info_list->name;
422	        unsigned int ByteSize =
423	            (acr_width % 8 == 0) ? acr_width / 8 : (acr_width / 8) + 1;
424	
425	        gdb_feature_builder_append_tag(
426	            &builder, "<vector id=\"acr_%d_t\" type=\"uint8\" count=\"%d\"/>",
427	            ByteSize * 8, ByteSize);
428	
429	
430	        for (unsigned int idx = 0; idx < acr_number; idx++) {
431	            char acr_reg_name[2048];
432	            char acr_type[16];
433	            snprintf(acr_reg_name, sizeof(acr_reg_name),
434	                     "%s_%u", acr_name, idx);
435	            snprintf(acr_type, sizeof(acr_type),
436	                     "acr_%d_t", ByteSize * 8);
437	            gdb_feature_builder_append_reg(&builder, acr_reg_name, acr_width,
438	                                           num_regs++, acr_type, "ace");
439	        }
440	        acr_info_list++;
441	    }
442	
443	    gdb_feature_builder_end(&builder);
444	
445	#if !defined(CONFIG_USER_ONLY)
446	    env->debugger = false;
447	#endif
448	
449	    return &cpu->dyn_ace_feature;
450	#endif
451	}
