static int riscv_gdb_set_csr(CPUState *cs, uint8_t *mem_buf, int n)
{
    RISCVCPU *cpu = RISCV_CPU(cs);
    CPURISCVState *env = &cpu->env;

    if (n < CSR_TABLE_SIZE) {
        target_ulong val = ldtul_p(mem_buf);
        int result;

        result = riscv_csrrw_debug(env, n, NULL, val, -1);
        if (result == RISCV_EXCP_NONE) {
            return sizeof(target_ulong);
        }
    }
    return 0;
}
```

This function:
- Parses the P-packet value from `mem_buf`
- Calls `riscv_csrrw_debug()` with a full write mask (`-1`)
- Returns success if the CSR operation succeeds

#### 2. **CSR Debug Interface** (`/home/nick/work/hybrid_sim/hybrid_qemu/target/riscv/csr.c:5151-5165`)

